package ir.tahamohamadi.blog.tag; import jakarta.persistence.*; import lombok.*; import java.io.Serializable; import java.util.*;
@Embeddable @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPostTagId implements Serializable { @Column(name="blog_post_id") private UUID blogPostId; @Column(name="tag_id") private UUID tagId; public BlogPostTagId(UUID postId,UUID tagId){this.blogPostId=Objects.requireNonNull(postId);this.tagId=Objects.requireNonNull(tagId);} @Override public boolean equals(Object o){return this==o||(o instanceof BlogPostTagId i&&blogPostId.equals(i.blogPostId)&&tagId.equals(i.tagId));} @Override public int hashCode(){return Objects.hash(blogPostId,tagId);} }
